import{_ as i,C as o,o as e,c as d,a0 as a,b as s,w as r,a as l,E as c,a1 as h}from"./chunks/framework.B3sz4m_N.js";const p=""+new URL("../report/agentic-techniques-07-action-plan.png",import.meta.url).href,C=JSON.parse('{"title":"Action Plan","description":"Phased implementation plan for adopting agentic engineering techniques, ranked by impact-to-effort ratio.","frontmatter":{"title":"Action Plan","description":"Phased implementation plan for adopting agentic engineering techniques, ranked by impact-to-effort ratio."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/07-action-plan.md","filePath":"reports/agentic-engineering-techniques/07-action-plan.md"}'),g={name:"reports/agentic-engineering-techniques/07-action-plan.md"};function u(m,t,f,b,k,A){const n=o("Mermaid");return e(),d("div",null,[t[1]||(t[1]=a('<figure class="report-section-image-wrapper" aria-labelledby="fig-action-caption"><img src="'+p+'" alt="A mountaineer&#39;s route map showing base camp and numbered waypoints ascending to the summit" loading="lazy" class="report-section-image"><figcaption id="fig-action-caption">A phased ascent from quick wins to advanced capabilities</figcaption></figure><h2 id="_7-action-plan" tabindex="-1">7. Action Plan <a class="header-anchor" href="#_7-action-plan" aria-label="Permalink to &quot;7. Action Plan&quot;">​</a></h2><p>Recommendations are grouped into four phases, ranked by impact-to-effort ratio. Each phase builds on the previous — complete Phase 1 before starting Phase 2.</p><h3 id="phase-1-quick-wins-1–2-days" tabindex="-1">Phase 1: Quick Wins (1–2 days) <a class="header-anchor" href="#phase-1-quick-wins-1–2-days" aria-label="Permalink to &quot;Phase 1: Quick Wins (1–2 days)&quot;">​</a></h3><p>Low-effort changes that improve quality and speed immediately.</p><table tabindex="0"><thead><tr><th>#</th><th>Action</th><th>Effort</th><th>Impact</th><th>Gap ref</th></tr></thead><tbody><tr><td>1</td><td><strong>Parallelise Phase 1 agents</strong> — update orchestration docs to run architect + dev-lead + devops + governance in a single Task message</td><td>1 hr</td><td>High</td><td>A</td></tr><tr><td>2</td><td><strong>Enrich skill descriptions</strong> — add trigger terms and &quot;NOT for&quot; scope boundaries to all skill frontmatter</td><td>2 hrs</td><td>High</td><td>H</td></tr><tr><td>3</td><td><strong>Add uncertainty handling</strong> — add standardised <code>## Handling Uncertainty</code> section to all skills</td><td>2 hrs</td><td>High</td><td>D</td></tr><tr><td>4</td><td><strong>Populate the strategist skill</strong> — create SKILL.md with role, focus, constraints, and output structure</td><td>2 hrs</td><td>High</td><td>—</td></tr><tr><td>5</td><td><strong>Add stopping conditions</strong> — add explicit stop criteria to the one-shot runner and critic skill</td><td>1 hr</td><td>Medium</td><td>—</td></tr><tr><td>6</td><td><strong>Create prompt architecture map</strong> — document context composition by phase in <code>PROMPT_ARCHITECTURE.md</code></td><td>1 hr</td><td>Medium</td><td>L</td></tr></tbody></table><p><strong>Expected outcome:</strong> More consistent agent activation, better handling of ambiguous inputs, and a documented orchestration structure for debugging.</p><h3 id="phase-2-structural-improvements-3–5-days" tabindex="-1">Phase 2: Structural Improvements (3–5 days) <a class="header-anchor" href="#phase-2-structural-improvements-3–5-days" aria-label="Permalink to &quot;Phase 2: Structural Improvements (3–5 days)&quot;">​</a></h3><p>Changes that require creating new content but don&#39;t alter the fundamental workflow.</p><table tabindex="0"><thead><tr><th>#</th><th>Action</th><th>Effort</th><th>Impact</th><th>Gap ref</th></tr></thead><tbody><tr><td>7</td><td><strong>Add few-shot examples</strong> — add one truncated input/output example to architect, critic, and reconciliation skills</td><td>4 hrs</td><td>High</td><td>C</td></tr><tr><td>8</td><td><strong>Standardise spec format</strong> — create a structured initiative intake format with YAML frontmatter that agents can reference by path</td><td>3 hrs</td><td>High</td><td>F</td></tr><tr><td>9</td><td><strong>Make one-shot runner self-contained</strong> — reference spec file path, inline agent directory with trigger terms and scope boundaries</td><td>3 hrs</td><td>Medium</td><td>—</td></tr><tr><td>10</td><td><strong>Add model assumptions</strong> — add <code>## Model Assumptions</code> section to domain-dependent skills (architect, governance, devops)</td><td>2 hrs</td><td>Medium</td><td>G</td></tr><tr><td>11</td><td><strong>Create resource directory</strong> — add <code>resources/</code> alongside key skills with approved tooling lists and reference checklists</td><td>3 hrs</td><td>Medium</td><td>J</td></tr><tr><td>12</td><td><strong>Document debugging methodology</strong> — add agent debugging process (Classify → Isolate → Verbose → Simplify → Contrast) to orchestration folder</td><td>1 hr</td><td>Medium</td><td>K</td></tr></tbody></table><p><strong>Expected outcome:</strong> Skills produce more consistent output, the one-shot runner is reproducible, and there&#39;s a methodology for diagnosing quality issues.</p><h3 id="phase-3-evaluation-and-learning-1–2-weeks" tabindex="-1">Phase 3: Evaluation and Learning (1–2 weeks) <a class="header-anchor" href="#phase-3-evaluation-and-learning-1–2-weeks" aria-label="Permalink to &quot;Phase 3: Evaluation and Learning (1–2 weeks)&quot;">​</a></h3><p>Changes that require developing evaluation infrastructure and feedback mechanisms.</p><table tabindex="0"><thead><tr><th>#</th><th>Action</th><th>Effort</th><th>Impact</th><th>Gap ref</th></tr></thead><tbody><tr><td>13</td><td><strong>Create golden examples</strong> — for architect, critic, and reconciliation: one known-good input paired with expected output and 3–5 constraint checks</td><td>6 hrs</td><td>High</td><td>E</td></tr><tr><td>14</td><td><strong>Pilot the rubric</strong> — run the 15-criteria evaluation rubric against the top 3 skills, score results, record findings</td><td>3 hrs</td><td>Medium</td><td>—</td></tr><tr><td>15</td><td><strong>Add improvement logging</strong> — create a post-run improvement log template and discipline to fill it after each workflow run</td><td>2 hrs</td><td>Medium</td><td>I</td></tr><tr><td>16</td><td><strong>Implement context isolation</strong> — restructure the one-shot runner to use Cursor&#39;s Task tool, with each agent running as a subagent returning structured summaries</td><td>4 hrs</td><td>High</td><td>B</td></tr><tr><td>17</td><td><strong>Update orchestration docs</strong> — update <code>02_RUN_WORKFLOW.md</code>, <code>06_ONE_SHOT_RUNNER_PROMPT.md</code>, and <code>08_ORCHESTRATION_CHECKLIST.md</code> to reflect new parallel + isolated structure</td><td>3 hrs</td><td>Medium</td><td>—</td></tr></tbody></table><p><strong>Expected outcome:</strong> Systematic quality measurement, a feedback loop for continuous improvement, and context-isolated agent execution.</p><h3 id="phase-4-advanced-future" tabindex="-1">Phase 4: Advanced (future) <a class="header-anchor" href="#phase-4-advanced-future" aria-label="Permalink to &quot;Phase 4: Advanced (future)&quot;">​</a></h3><p>Larger changes to pursue once Phases 1–3 are stable.</p><table tabindex="0"><thead><tr><th>#</th><th>Action</th><th>Effort</th><th>Impact</th><th>Gap ref</th></tr></thead><tbody><tr><td>18</td><td><strong>Add Plan-Build-Review wrapper</strong> — create Plan phase (orchestrator reviews intake, creates research plan) and Review phase (run rubric against reconciled output) around the existing Build workflow</td><td>1 week</td><td>High</td><td>—</td></tr><tr><td>19</td><td><strong>Build meta-cognitive skill</strong> — create a skill that audits other skills against the evaluation rubric and proposes improvements</td><td>1 week</td><td>Medium</td><td>—</td></tr><tr><td>20</td><td><strong>Implement Expert Swarm</strong> — for portfolio workflow, run multiple initiatives in parallel using the Expert Swarm pattern with shared expertise inheritance</td><td>1 week</td><td>Medium</td><td>—</td></tr><tr><td>21</td><td><strong>Create eval-driven development workflow</strong> — write eval cases before modifying skills; run smoke tests on every skill change</td><td>1 week</td><td>Medium</td><td>—</td></tr></tbody></table><p><strong>Expected outcome:</strong> The workflow advances from Level 4–5 to Level 5–6 on the Prompt Maturity Model, with systematic self-improvement.</p><hr><h3 id="implementation-priorities-visualised" tabindex="-1">Implementation priorities visualised <a class="header-anchor" href="#implementation-priorities-visualised" aria-label="Permalink to &quot;Implementation priorities visualised&quot;">​</a></h3>',21)),(e(),s(h,null,{default:r(()=>[c(n,{id:"mermaid-496",class:"mermaid",graph:"gantt%0A%20%20%20%20title%20Agentic%20Engineering%20Techniques%20%E2%80%94%20Implementation%20Phases%0A%20%20%20%20dateFormat%20%20YYYY-MM-DD%0A%20%20%20%20axisFormat%20%20%25b%20%25d%0A%0A%20%20%20%20section%20Phase%201%20-%20Quick%20Wins%0A%20%20%20%20Parallelise%20agents%20%20%20%20%20%20%20%20%20%20%20%3Aa1%2C%202026-03-10%2C%201d%0A%20%20%20%20Enrich%20skill%20descriptions%20%20%20%20%3Aa2%2C%202026-03-10%2C%201d%0A%20%20%20%20Uncertainty%20handling%20%20%20%20%20%20%20%20%20%3Aa3%2C%202026-03-10%2C%201d%0A%20%20%20%20Populate%20strategist%20%20%20%20%20%20%20%20%20%20%3Aa4%2C%202026-03-11%2C%201d%0A%20%20%20%20Stopping%20conditions%20%20%20%20%20%20%20%20%20%20%3Aa5%2C%202026-03-11%2C%201d%0A%20%20%20%20Prompt%20architecture%20map%20%20%20%20%20%20%3Aa6%2C%202026-03-11%2C%201d%0A%0A%20%20%20%20section%20Phase%202%20-%20Structural%0A%20%20%20%20Few-shot%20examples%20%20%20%20%20%20%20%20%20%20%20%20%3Ab1%2C%202026-03-12%2C%202d%0A%20%20%20%20Standardise%20spec%20format%20%20%20%20%20%20%3Ab2%2C%202026-03-12%2C%202d%0A%20%20%20%20Self-contained%20runner%20%20%20%20%20%20%20%20%3Ab3%2C%202026-03-14%2C%201d%0A%20%20%20%20Model%20assumptions%20%20%20%20%20%20%20%20%20%20%20%20%3Ab4%2C%202026-03-14%2C%201d%0A%20%20%20%20Resource%20directory%20%20%20%20%20%20%20%20%20%20%20%3Ab5%2C%202026-03-17%2C%201d%0A%20%20%20%20Debugging%20methodology%20%20%20%20%20%20%20%20%3Ab6%2C%202026-03-17%2C%201d%0A%0A%20%20%20%20section%20Phase%203%20-%20Evaluation%0A%20%20%20%20Golden%20examples%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Ac1%2C%202026-03-18%2C%203d%0A%20%20%20%20Pilot%20rubric%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Ac2%2C%202026-03-18%2C%202d%0A%20%20%20%20Improvement%20logging%20%20%20%20%20%20%20%20%20%20%3Ac3%2C%202026-03-20%2C%201d%0A%20%20%20%20Context%20isolation%20%20%20%20%20%20%20%20%20%20%20%20%3Ac4%2C%202026-03-21%2C%202d%0A%20%20%20%20Update%20orchestration%20docs%20%20%20%20%3Ac5%2C%202026-03-24%2C%202d%0A%0A%20%20%20%20section%20Phase%204%20-%20Advanced%0A%20%20%20%20Plan-Build-Review%20wrapper%20%20%20%20%3Ad1%2C%202026-03-31%2C%205d%0A%20%20%20%20Meta-cognitive%20skill%20%20%20%20%20%20%20%20%20%3Ad2%2C%202026-04-07%2C%205d%0A%20%20%20%20Expert%20Swarm%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Ad3%2C%202026-04-14%2C%205d%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<hr><h3 id="techniques-deliberately-excluded" tabindex="-1">Techniques deliberately excluded <a class="header-anchor" href="#techniques-deliberately-excluded" aria-label="Permalink to &quot;Techniques deliberately excluded&quot;">​</a></h3><p>These techniques are present in the book but not recommended for this workflow at this stage:</p><table tabindex="0"><thead><tr><th>Technique</th><th>Reason for exclusion</th></tr></thead><tbody><tr><td>A/B testing for prompts</td><td>Research-oriented workflow, not user-facing; insufficient run volume to generate statistical significance</td></tr><tr><td>Agent Teams / TeammateTool</td><td>Experimental feature, not stable for production research workflows</td></tr><tr><td>Automated CI/CD eval integration</td><td>Overkill for a research site; target &quot;scripted&quot; evaluation tier instead</td></tr><tr><td>Context Contracts with JSON schemas</td><td>Premature; agent count is manageable without formal schemas</td></tr><tr><td>Token-level cost tracking</td><td>Requires API-level access not available in Cursor; cost-governor skill handles policy-level budgeting</td></tr><tr><td>Model-Native Swarm Orchestration</td><td>Kimi K2.5-specific pattern, not applicable to Cursor/Claude</td></tr><tr><td>Production Multi-Agent Systems</td><td>Scale (10+ agents in production with recovery) not needed for research workflow</td></tr></tbody></table><hr><h3 id="key-takeaway" tabindex="-1">Key takeaway <a class="header-anchor" href="#key-takeaway" aria-label="Permalink to &quot;Key takeaway&quot;">​</a></h3><p>The existing workflow has strong prompt principles (clarity, structure, constraints) and well-designed agent specialisation. The book validates these choices.</p><p>The four highest-leverage improvements are:</p><ol><li><strong>Parallelise</strong> independent agents — immediate speed gain, zero quality risk</li><li><strong>Add examples</strong> to skills — highest impact on output consistency</li><li><strong>Start evaluating</strong> with golden examples — transforms tinkering into engineering</li><li><strong>Implement context isolation</strong> — prevents quality degradation in reconciliation</li></ol><p>These four changes address the book&#39;s central thesis: that agentic engineering succeeds through disciplined context management, structured evaluation, and design over improvisation.</p><hr><h3 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h3><ul><li><a href="https://jayminwest.com/agentic-engineering-book" target="_blank" rel="noreferrer">Agentic Engineering Book</a> — Jaymin West</li><li><a href="https://jayminwest.com/agentic-engineering-book/2-prompt" target="_blank" rel="noreferrer">Chapter 2: Prompt</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/4-context" target="_blank" rel="noreferrer">Chapter 4: Context</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/5-tool-use/5-skills-and-meta-tools" target="_blank" rel="noreferrer">Chapter 5: Tool Use — Skills and Meta-Tools</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/6-patterns/3-orchestrator-pattern" target="_blank" rel="noreferrer">Chapter 6: Patterns — Orchestrator Pattern</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/6-patterns/8-expert-swarm-pattern" target="_blank" rel="noreferrer">Chapter 6: Patterns — Expert Swarm</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/7-practices/2-evaluation" target="_blank" rel="noreferrer">Chapter 7: Practices — Evaluation</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/8-mental-models/2-prompt-maturity-model" target="_blank" rel="noreferrer">Chapter 8: Mental Models — Prompt Maturity Model</a></li><li><a href="https://jayminwest.com/agentic-engineering-book/8-mental-models/3-specs-as-source-code" target="_blank" rel="noreferrer">Chapter 8: Mental Models — Specs as Source Code</a></li></ul>',13))])}const v=i(g,[["render",u]]);export{C as __pageData,v as default};
